// ─── Deterministic fixtures (shared with the golden generator) ──────────────

const SECONDS_PER_DAY = 86400
const START_TIME = Date.UTC(2024, 0, 1) / 1000

function makeOhlcv(bars: number, priceFn: (i: number) => number, range = 0.5): OhlcvRow[] {
  const out: OhlcvRow[] = []
  for (let i = 0; i < bars; i++) {
    const close = priceFn(i)
    const open = i === 0 ? close : priceFn(i - 1)
    out.push({
      time: START_TIME + i * SECONDS_PER_DAY,
      open,
      high: Math.max(open, close) + range,
      low: Math.min(open, close) - range,
      close,
      volume: 1_000_000 + (i % 7) * 50_000,
    })
  }
  return out
}

/**
 * Exp uptrend at `rate`/bar with single-bar crashes (level ×= crashFactor) at
 * each bar in `crashes`; growth continues from the crashed level at
 * `tailRate`/bar after the FIRST crash (tailRate defaults to rate).
 */
function multiDipSeries(
  bars: number,
  crashes: number[],
  rate = 0.004,
  crashFactor = 0.64,
  tailRate?: number,
): OhlcvRow[] {
  const closes: number[] = []
  let level = 100
  let g = rate
  const crashSet = new Set(crashes)
  for (let i = 0; i < bars; i++) {
    if (i > 0) level *= 1 + g
    if (crashSet.has(i)) {
      level *= crashFactor
      g = tailRate ?? rate
    }
    closes.push(level)
  }
  return makeOhlcv(bars, (i) => closes[i], 0.2)
}

const dipRecover380 = () => multiDipSeries(380, [300], 0.004, 0.64, 0.005)
const dipLoss380 = () => multiDipSeries(380, [300], 0.004, 0.64, -0.003)
const dipBar301 = () => multiDipSeries(301, [300]) // last bar IS the crash bar

function sigInputs(rows: OhlcvRow[]) {
  const closes = rows.map((r) => r.close)
  const bars = rows.map(({ open, high, low, close }) => ({ open, high, low, close }))
  const ohlcv = rows.map((r) => ({
    open: r.open, high: r.high, low: r.low, close: r.close,
    volume: r.volume ?? 0, time: r.time,
  }))
  return { closes, bars, ohlcv, price: closes[closes.length - 1] }
}

