describe('computeBuyAndHoldReturn + tradingDaysPerYear — exact pins', () => {
  it('reinvests the ex-date dividend at that bar close', () => {
    const rows: OhlcvRow[] = [
      { time: START_TIME, open: 100, high: 101, low: 99, close: 100, volume: 1 },
      { time: START_TIME + SECONDS_PER_DAY, open: 100, high: 105, low: 99, close: 104, volume: 1, dividend: 2 },
      { time: START_TIME + 2 * SECONDS_PER_DAY, open: 104, high: 111, low: 103, close: 110, volume: 1 },
    ]
    // shares = 1 + 2/104; final = shares × 110; return = final/100 − 1
    expect(computeBuyAndHoldReturn(rows)).toBeCloseTo(0.121154, 6)
    expect(computeBuyAndHoldReturn(rows.slice(0, 1))).toBe(0)
  })

  it('365d for known crypto tickers and crypto sector, 252d otherwise', () => {
    expect(tradingDaysPerYear('btc', '')).toBe(365) // case-insensitive ticker
    expect(tradingDaysPerYear('AAPL', 'Crypto')).toBe(365) // sector match
    expect(tradingDaysPerYear('AAPL', 'Technology')).toBe(252)
  })
})

