describe('piecewiseRsiScore — exact breakpoint pins', () => {
  it('maps every segment and boundary exactly', () => {
    expect(piecewiseRsiScore(NaN)).toBe(0)
    expect(piecewiseRsiScore(25)).toBe(1.0)
    expect(piecewiseRsiScore(30)).toBe(1.0) // (50-30)/20 — continuous at 30
    expect(piecewiseRsiScore(40)).toBeCloseTo(0.5, 10)
    expect(piecewiseRsiScore(50)).toBe(0)
    expect(piecewiseRsiScore(55)).toBeCloseTo(-0.25, 10)
    expect(piecewiseRsiScore(70)).toBeCloseTo(-1.0, 10) // -(70-50)/20 — continuous at 70
    expect(piecewiseRsiScore(75)).toBe(-1.0)
  })
})

describe('isGoldenCross / hasPositiveMomentum / isMACompression — boundaries', () => {
  it('golden cross: EMA50 above EMA200 on a rising series, false on falling / short', () => {
    const rising = Array.from({ length: 250 }, (_, i) => 100 + i)
    const falling = Array.from({ length: 250 }, (_, i) => 350 - i)
    expect(isGoldenCross(rising)).toBe(true)
    expect(isGoldenCross(falling)).toBe(false)
    expect(isGoldenCross(rising.slice(0, 199))).toBe(false) // < 200 guard
  })

  it('momentum: strict > over exactly `period` bars back', () => {
    const rising = Array.from({ length: 64 }, (_, i) => 100 + i)
    expect(hasPositiveMomentum(rising)).toBe(true)
    expect(hasPositiveMomentum(rising.slice(0, 63))).toBe(false) // needs period+1
    expect(hasPositiveMomentum(Array.from({ length: 64 }, () => 100))).toBe(false) // flat, strict >
    expect(hasPositiveMomentum([100, 101, 102], 2)).toBe(true) // custom period
    expect(hasPositiveMomentum([102, 101, 100], 2)).toBe(false)
  })

  it('MA compression: flat ribbon compresses; steep trend does not; tolerance is strict <', () => {
    const flat = Array.from({ length: 240 }, () => 100)
    expect(isMACompression(flat)).toBe(true) // spread 0 < 0.05
    expect(isMACompression(flat, 0)).toBe(false) // 0 < 0 is false
    const steep = Array.from({ length: 240 }, (_, i) => 100 * Math.pow(1.01, i))
    expect(isMACompression(steep)).toBe(false)
    expect(isMACompression(flat.slice(0, 199))).toBe(false) // < 200 guard
  })
})

describe('detectBullishDivergence — crafted trough pins', () => {
  // Two price troughs (15 shallow, 25 deeper) inside the 20-bar lookback tail.
  const divCloses = (() => {
    const c = Array.from({ length: 30 }, () => 100)
    c[15] = 95; c[14] = 97; c[16] = 97
    c[25] = 90; c[24] = 93; c[26] = 93
    return c
  })()
  const divRsi = (() => {
    const r = divCloses.map(() => 50)
    r[15] = 25; r[25] = 40 // RSI higher low at the deeper price low
    return r
  })()

  it('price lower low + RSI higher low (< 65) → divergence', () => {
    expect(detectBullishDivergence(divCloses, divRsi)).toBe(true)
  })
  it('RSI second low at/above 65 → no divergence (soft cap)', () => {
    const r = [...divRsi]; r[25] = 66
    expect(detectBullishDivergence(divCloses, r)).toBe(false)
  })
  it('RSI lower low → no divergence', () => {
    const r = [...divRsi]; r[25] = 20
    expect(detectBullishDivergence(divCloses, r)).toBe(false)
  })
  it('price higher low → no divergence', () => {
    const c = [...divCloses]; c[25] = 96
    expect(detectBullishDivergence(c, divRsi)).toBe(false)
  })
  it('insufficient bars → false', () => {
    expect(detectBullishDivergence(divCloses.slice(0, 10), divRsi.slice(0, 10))).toBe(false)
  })
})

describe('detectVolumeClimax — crafted threshold pins', () => {
  function climaxBars(volMult: number, bodyPct: number, closeAboveMid: boolean) {
    const bars = Array.from({ length: 25 }, () => ({
      open: 100, high: 101, low: 99, close: 100, volume: 1000,
    }))
    bars[23] = { open: 100, high: 104, low: 96, close: 98, volume: 1000 } // prev mid = 100
    const open = 110
    const close = open * (1 - bodyPct)
    bars[24] = {
      open, high: 111, low: close - 1,
      close: closeAboveMid ? Math.max(close, 100.5) : Math.min(close, 99.5),
      volume: 1000 * volMult,
    }
    return bars
  }

  it('spike >2×, bearish body >1.5%, close above prev mid → climax', () => {
    expect(detectVolumeClimax(climaxBars(3, 0.05, true))).toBe(true)
  })
  it('volume EXACTLY 2× average is not a spike (strict >)', () => {
    expect(detectVolumeClimax(climaxBars(2, 0.05, true))).toBe(false)
  })
  it('body ≤1.5% is not a panic candle', () => {
    expect(detectVolumeClimax(climaxBars(3, 0.01, true))).toBe(false)
  })
  it('close below prev-range midpoint is not a recovery', () => {
    expect(detectVolumeClimax(climaxBars(3, 0.05, false))).toBe(false)
  })
})

describe('priceWasNearSmaRecently — threshold pins', () => {
  const farBelow = Array.from({ length: 240 }, (_, i) => (i < 200 ? 100 : 80))
  const flat = Array.from({ length: 240 }, () => 100)

  it('20% below SMA for the whole window → false at the default 5% threshold', () => {
    expect(priceWasNearSmaRecently(farBelow)).toBe(false)
  })
  it('flat at the SMA → true; < 220 bars → false; wide threshold flips the far case', () => {
    expect(priceWasNearSmaRecently(flat)).toBe(true)
    expect(priceWasNearSmaRecently(flat.slice(0, 219))).toBe(false)
    expect(priceWasNearSmaRecently(farBelow, 25)).toBe(true)
  })
})
